/*!
 * SweetAlert Simplified Popup System
 */

window.Swal = {

    fire({
        title = '',
        text = '',
        icon = 'info',
        confirmButtonText = 'OK'
    }) {

        const overlay =
            document.createElement('div');

        overlay.style.position =
            'fixed';

        overlay.style.top =
            '0';

        overlay.style.left =
            '0';

        overlay.style.width =
            '100%';

        overlay.style.height =
            '100%';

        overlay.style.background =
            'rgba(0,0,0,0.7)';

        overlay.style.display =
            'flex';

        overlay.style.alignItems =
            'center';

        overlay.style.justifyContent =
            'center';

        overlay.style.zIndex =
            '99999';

        const modal =
            document.createElement('div');

        modal.style.background =
            '#111827';

        modal.style.padding =
            '40px';

        modal.style.borderRadius =
            '24px';

        modal.style.width =
            '90%';

        modal.style.maxWidth =
            '420px';

        modal.style.textAlign =
            'center';

        modal.style.color =
            '#ffffff';

        modal.innerHTML = `
            <div style="font-size:54px;margin-bottom:16px;">
                ${getIcon(icon)}
            </div>

            <h2 style="margin-bottom:14px;">
                ${title}
            </h2>

            <p style="margin-bottom:24px;color:#94a3b8;">
                ${text}
            </p>

            <button
                id="swalConfirmBtn"
                style="
                    background:#6366f1;
                    border:none;
                    color:white;
                    padding:14px 24px;
                    border-radius:12px;
                    cursor:pointer;
                    font-weight:bold;
                "
            >
                ${confirmButtonText}
            </button>
        `;

        overlay.appendChild(modal);

        document.body.appendChild(
            overlay
        );

        document
            .getElementById(
                'swalConfirmBtn'
            )
            .addEventListener(
                'click',
                () => {

                    overlay.remove();
                }
            );
    }
};

function getIcon(icon) {

    const icons = {

        success: '✅',

        error: '❌',

        warning: '⚠️',

        info: 'ℹ️'
    };

    return icons[icon] || 'ℹ️';
}